// This function should check if all exposed ports in a service's ports are assigned to a service.
// If a port is not assigned, it should return an error message indicating the port number and service name.
// If all ports are assigned, it should return an empty array.
function validatePorts(composeFile) {
  const lines = composeFile.split('\n');
  const services = {};

  for (const line of lines) {
    if (line.startsWith('  ports:')) {
      const service = lines[lines.indexOf(line)].split(':')[0].trim();
      const ports = lines[lines.indexOf(line) + 1].split('  ').filter(Boolean)[0].split(',').map(port => port.trim());
      services[service] = ports.map(port => port.split(':')[0].split('-')[0].trim());
    }
  }

  const assignedPorts = {};
  for (const service in services) {
    for (const port of services[service]) {
      assignedPorts[port] = service;
    }
  }

  const unassignedPorts = [];
  for (const service in services) {
    for (const port of services[service]) {
      if (!assignedPorts[port]) {
        unassignedPorts.push(port + ' is not assigned to service ' + service);
      }
    }
  }

  return unassignedPorts;
}

